class Solution:
    def longestZigZag(self, root):
        best = [0]
        def dfs(node):
            l = dfs(node.left) if node.left else None
            r = dfs(node.right) if node.right else None
            left_start = 1 + l[1] if node.left else 0
            right_start = 1 + r[0] if node.right else 0
            if left_start > best[0]:
                best[0] = left_start
            if right_start > best[0]:
                best[0] = right_start
            return (left_start, right_start)
        dfs(root)
        return best[0]

