class Solution:
    def longestZigZag(self, root):
        self.ans = 0
        def dfs(node, direction, length):
            if not node:
                return
            if length > self.ans:
                self.ans = length
            if direction == 'left':
                dfs(node.left, 'right', length + 1)
                dfs(node.right, 'left', 1)
            else:
                dfs(node.right, 'left', length + 1)
                dfs(node.left, 'right', 1)
        dfs(root, 'left', 0)
        dfs(root, 'right', 0)
        return self.ans

