var longestZigZag = function(root) {
    let ans = 0;
    function dfs(node, direction, length) {
        if (!node) return;
        if (length > ans) ans = length;
        if (direction === 'left') {
            dfs(node.left, 'right', length + 1);
            dfs(node.right, 'left', 1);
        } else {
            dfs(node.right, 'left', length + 1);
            dfs(node.left, 'right', 1);
        }
    }
    dfs(root, 'left', 0);
    dfs(root, 'right', 0);
    return ans;
};
